(In reply to Mark Millard from comment #36)

(I should note that I'm not looking at the exact
u-boot sources but the 2020.04 sources I had around
from a prior investigation of some behavior.)

The earlier ERROR message is from:

efi_status_t efi_disk_register(void)
{
. . .
        for (uclass_first_device_check(UCLASS_BLK, &dev); dev;
             uclass_next_device_check(&dev)) {
                struct blk_desc *desc = dev_get_uclass_platdata(dev);
                const char *if_typename = blk_get_if_type_name(desc->if_type);

                /* Add block device for the full device */
                printf("Scanning disk %s...\n", dev->name);
                ret = efi_disk_add_dev(NULL, NULL, if_typename,
                                        desc, desc->devnum, 0, 0, &disk);
                if (ret == EFI_NOT_READY) {
                        printf("Disk %s not ready\n", dev->name);
                        continue;
                }
                if (ret) {
                        printf("ERROR: failure to add disk device %s, r = %lu\n",
                               dev->name, ret & ~EFI_ERROR_MASK);
                        return ret;
                }
. . .
        }

(The "Scanning disk" message matches the above.)

There is seaprate code in the routine based on
CONFIG_BLK being defined (above case) vs. not
(below case) that looks like:

        for (if_type = 0; if_type < IF_TYPE_COUNT; if_type++) {
                const struct blk_driver *cur_drvr;
                const char *if_typename;

                cur_drvr = blk_driver_lookup_type(if_type);
                if (!cur_drvr)
                        continue;

                if_typename = cur_drvr->if_typename;
                printf("Scanning disks on %s...\n", if_typename);
                for (i = 0; i < 4; i++) {
                        struct blk_desc *desc;
                        char devname[32] = { 0 }; /* dp->str is u16[32] long */

                        desc = blk_get_devnum_by_type(if_type, i);
                        if (!desc)
                                continue;
                        if (desc->type == DEV_TYPE_UNKNOWN)
                                continue;

                        snprintf(devname, sizeof(devname), "%s%d",
                                 if_typename, i);

                        /* Add block device for the full device */
                        ret = efi_disk_add_dev(NULL, NULL, if_typename, desc,
                                               i, 0, 0, &disk);
                        if (ret == EFI_NOT_READY) {
                                printf("Disk %s not ready\n", devname);
                                continue;
                        }
                        if (ret) {
                                printf("ERROR: failure to add disk device %s, r = %lu\n",
                                       devname, ret & ~EFI_ERROR_MASK);
                                return ret;
                        }
